//
// Boots the runtime server using the loaded `*config.Config` as the
// single source of truth. Tracer + meter setup is delegated to the
// library helpers [craftotel.InitFromConfig] and
// [metrics.InitFromConfig] so the exporter selection
// (none / stdout / otlp_grpc / otlp_http / prometheus) lives next to
// the SDK, not inline here. The only knob exposed to the deployer is
// `config.yaml` (or the matching `CRAFTGO_*` environment variables).

package main

import (
	"context"
	_ "embed"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/craftgodotdev/craftgo/pkg/log"
	"github.com/craftgodotdev/craftgo/pkg/metrics"
	craftotel "github.com/craftgodotdev/craftgo/pkg/otel"
	"github.com/craftgodotdev/craftgo/pkg/server"

	"github.com/craftgodotdev/craftgo/example/ecommerce/config"
	"github.com/craftgodotdev/craftgo/example/ecommerce/internal/middleware"
	"github.com/craftgodotdev/craftgo/example/ecommerce/internal/routes"
	"github.com/craftgodotdev/craftgo/example/ecommerce/svccontext"
)

// openapiSpec is the generated OpenAPI document, embedded so the docs page
// (config.docs) serves it without shipping a separate file.
//
//go:embed docs/openapi.yaml
var openapiSpec []byte

func main() {
	cfg, err := config.Load(config.Path())
	if err != nil {
		log.Default().Error("load config", log.Err(err))
		os.Exit(1)
	}

	// config.logging.level retunes the shared logger for both the server
	// and the generated logic layer. An unrecognised value keeps the
	// info default.
	if lvl, ok := log.ParseLevel(cfg.Logging.Level); ok {
		log.SetLevel(lvl)
	}

	ctx := context.Background()

	tracerProvider, err := craftotel.InitFromConfig(ctx, cfg.OTel)
	if err != nil {
		log.Default().Error("init otel", log.Err(err))
		os.Exit(1)
	}

	metricsProvider, adminSrv, err := metrics.InitFromConfig(ctx, cfg.Metrics)
	if err != nil {
		log.Default().Error("init metrics", log.Err(err))
		os.Exit(1)
	}
	if adminSrv != nil {
		log.Default().Info("metrics scrape listening", log.String("addr", adminSrv.Addr()), log.String("path", adminSrv.Path()))
		go func() {
			if err := <-adminSrv.ErrCh(); err != nil {
				log.Default().Error("admin metrics listener", log.Err(err))
			}
		}()
	}

	svc := svccontext.NewServiceContext(cfg)

	// Each design-declared middleware lives on the embedded
	// Middlewares struct of ServiceContext. Wire each field once at
	// startup with whatever params your impl needs.
	svc.AuthRequired = middleware.NewAuthRequiredMiddleware()
	svc.BodyLimit = middleware.NewBodyLimitMiddleware()
	svc.CORS = middleware.NewCORSMiddleware()
	svc.RateLimit = middleware.NewRateLimitMiddleware()
	svc.RequestID = middleware.NewRequestIDMiddleware()
	svc.Timeout = middleware.NewTimeoutMiddleware()

	// Build the Server and attach runtime globals via Use. Order
	// matters: OTel opens the span first so AccessLog sees the trace
	// ids on ctx (via `WithContext`); the same `otelhttp.NewHandler`
	// invocation records `http.server.duration` / `request.size` /
	// `response.size` against the configured MeterProvider so no
	// separate metrics middleware is needed.
	srv := server.New(svc)
	srv.Use(craftotel.HTTPMiddleware(cfg.OTel.ServiceName))
	srv.Use(server.AccessLog(srv.Logger()))
	// Global per-request guards. Per-method `@timeout` / `@maxBodySize`
	// decorators wrap inner so they can tighten (never loosen) these
	// defaults. Zero values from config skip the wrap entirely.
	if cfg.Server.HandlerTimeout > 0 {
		srv.Use(server.Timeout(cfg.Server.HandlerTimeout))
	}
	if cfg.Server.MaxBodySize > 0 {
		srv.Use(server.BodyLimit(cfg.Server.MaxBodySize))
	}
	if cfg.Server.Compression.Enabled {
		srv.Use(server.Compress(server.CompressOptions{
			MinSize: cfg.Server.Compression.MinSize,
			Level:   cfg.Server.Compression.Level,
		}))
	}

	// One call wires every service. The umbrella RegisterAll is
	// generated from the DSL service set on every `craftgo gen`.
	routes.RegisterAll(srv, svc)

	// Serve the API-reference docs (config.docs). The OpenAPI document is
	// embedded above; the UI assets load from a CDN.
	if cfg.Docs.Enabled {
		srv.ServeDocs(server.DocsOptions{
			Spec:     openapiSpec,
			UI:       cfg.Docs.UI,
			Path:     cfg.Docs.Path,
			SpecPath: cfg.Docs.SpecPath,
		})
	}

	go func() {
		log.Default().Info("listening", log.String("addr", cfg.Server.Addr))
		if err := srv.Start(cfg.Server.Addr); err != nil && err != http.ErrServerClosed {
			log.Default().Error("server start", log.Err(err))
			os.Exit(1)
		}
	}()

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, syscall.SIGINT, syscall.SIGTERM)
	<-stop

	shutdownCtx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	_ = srv.Stop(shutdownCtx)
	if adminSrv != nil {
		_ = metrics.ShutdownAdmin(shutdownCtx, adminSrv.HTTPServer())
	}
	if metricsProvider != nil {
		// Drain any pending OTLP push batch before exit. No-op for
		// pull-only setups; important for push so the final histogram
		// snapshot reaches the collector.
		_ = metricsProvider.Shutdown(shutdownCtx)
	}
	if tracerProvider != nil {
		_ = tracerProvider.Shutdown(shutdownCtx)
	}
}
